import re

# Find parenthesized spans
paren_spans = []
stack = []
for i,ch in enumerate(text):
    if ch == '(':
        stack.append(i)
    elif ch == ')':
        if stack:
            start = stack.pop()
            end = i+1  # exclusive index would be i+1 if we want to include closing )
            paren_spans.append((start, end, text[start:end]))
# Now filter spans that are followed by a bracket like " ["
valid_paren_spans = []
for start, end, s in paren_spans:
    # check next few chars for bracket or punctuation
    after = text[end:end+10]
    if '[' in after:
        valid_paren_spans.append((start, end, s))
valid_paren_spans, len(valid_paren_spans)
